class Solution {
    private int m;
    private int n;
    private int[] freeCells;
    private int freeCellsCount;

    public Solution(int m, int n) {
        this.m = m;
        this.n = n;
        this.freeCells = new int[m * n];
        this.freeCellsCount = m * n;
    }

    public int[] flip() {
        int randomIndex = (int) (Math.random() * freeCellsCount);
        int i = randomIndex / n;
        int j = randomIndex % n;
        freeCells[randomIndex] = -1;
        freeCellsCount--;
        return new int[] {i, j};
    }

    public void reset() {
        freeCellsCount = m * n;
        for (int i = 0; i < freeCells.length; i++) {
            freeCells[i] = i;
        }
    }
}
